import jakarta.servlet.http.HttpServletRequest;
import lombok.RequiredArgsConstructor;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

@RestController
@RequestMapping("/api/auth")
@RequiredArgsConstructor
public class AuthController {
    private final AuthService authService;

    @PostMapping("/login")
    public ResponseEntity<LoginResponse> login(
            @RequestBody LoginRequest request,
            HttpServletRequest httpRequest
    ) {
        LoginCommand command = new LoginCommand(
                request.email(),
                request.password(),
                request.deviceId(),
                request.deviceName(),
                httpRequest.getRemoteAddr()
        );

        AuthResult result = authService.login(command);

        return ResponseEntity.ok(
                new LoginResponse(
                        result.accessToken(),
                        result.refreshToken()
                )
        );
    }

    @PostMapping("/register")
    public ResponseEntity<RegisterResponse> register(
            @RequestBody RegisterRequest request
    ) {
        RegisterCommand command = new RegisterCommand(
                request.email(),
                request.password()
        );

        RegisterResult result = authService.register(command);

        return ResponseEntity.ok(
                new RegisterResponse(
                        "Đăng ký tài khoản thành công!",
                        "SUCCESS"
                )
        );
    }

    @PostMapping("/refresh")
    public ResponseEntity<RefreshResponse> refresh(
            @RequestBody RefreshRequest request
    ) {
        RefreshCommand command = new RefreshCommand(
                request.refreshToken(),
                request.deviceId()
        );

        AuthResult result = authService.refresh(command);

        return ResponseEntity.ok(
                new RefreshResponse(
                        result.accessToken(),
                        result.refreshToken()
                )
        );
    }

    @PostMapping("/logout")
    public ResponseEntity<LogoutResponse> logout(
            @RequestBody LogoutRequest request
    ) {
        LogoutCommand command = new LogoutCommand(
                request.refreshToken(),
                request.deviceId()
        );

        authService.logout(command);

        return ResponseEntity.ok(
                new LogoutResponse("Logged out successfully")
        );
    }

}

package com.backend.MusicApp.auth.crypto.impl;

import com.backend.MusicApp.auth.crypto.PasswordHasher;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.stereotype.Component;

@Component
public class BCryptPasswordHasher implements PasswordHasher {

    private final BCryptPasswordEncoder encoder = new BCryptPasswordEncoder();

    @Override
    public String hash(String rawPassword) {
        return encoder.encode(rawPassword);
    }

    @Override
    public boolean matches(String rawPassword, String hashedPassword) {
        return encoder.matches(rawPassword, hashedPassword);
    }
}

package com.backend.MusicApp.auth.crypto.impl;

import com.backend.MusicApp.auth.crypto.TokenHasher;
import org.springframework.stereotype.Component;

import java.nio.charset.StandardCharsets;
import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.util.HexFormat;

@Component
public class Sha256TokenHasher implements TokenHasher {

    @Override
    public String hash(String rawToken) {
        try {
            MessageDigest digest = MessageDigest.getInstance("SHA-256");
            byte[] hashed = digest.digest(rawToken.getBytes(StandardCharsets.UTF_8));
            return HexFormat.of().formatHex(hashed);
        } catch (NoSuchAlgorithmException e) {
            throw new IllegalStateException("SHA-256 not available", e);
        }
    }
}

