import com.backend.MusicApp.common.exception.LoginFailedException;
import jakarta.security.auth.message.AuthException;
import lombok.RequiredArgsConstructor;
import org.springframework.jdbc.core.JdbcTemplate;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.Instant;
import java.time.temporal.ChronoUnit;

@Service
@RequiredArgsConstructor
public class AuthServiceImpl implements AuthService {
    private final UserRepository userRepository;
    private final UserSessionRepository sessionRepository;
    private final PasswordHasher passwordHasher;
    private final TokenHasher tokenHasher;
    private final TokenGenerator tokenGenerator;
    private final TimeProvider timeProvider;

    @Transactional
    @Override
    public AuthResult login(LoginCommand command){
        User user = userRepository.findByEmail(command.email())
                .orElseThrow(() -> new LoginFailedException("Invalid email or password"));
        if (!"ACTIVE".equals(user.getStatus())) {
            throw new LoginFailedException("User is not active");
        }
        if (!passwordHasher.matches(command.password(), user.getPassword())) {
            throw new LoginFailedException("Invalid email or password");
        }

        sessionRepository.revokeAllByUserId(user.getId());

        String accessToken =
                tokenGenerator.generateAccessToken(user.getId(), user.getRole());

        String refreshToken =
                tokenGenerator.generateRefreshToken(user.getId());

        String refreshTokenHash = tokenHasher.hash(refreshToken);
        Instant now = timeProvider.now();
        UserSession session = new UserSession(
                user.getId(),
                refreshTokenHash,
                command.deviceId(),
                command.deviceName(),
                command.ipAddress(),
                now,
                now.plus(30, ChronoUnit.DAYS),
                null
        );

        sessionRepository.save(session);
        return new AuthResult(accessToken, refreshToken);
    }



    @Transactional
    @Override
    public RegisterResult register(RegisterCommand command) {
        if (userRepository.existsByEmail(command.email())) {
            throw new RuntimeException("Email already exists");
        }
        String passwordHash = passwordHasher.hash(command.password());


        User user = new User(
                null,
                command.email(),
                passwordHash,
                "USER",
                "ACTIVE",
                timeProvider.now()
        );
        long userId = userRepository.saveNonPostgre(user);
        return new RegisterResult(userId, user.getEmail());
    }

    @Transactional
    @Override
    public AuthResult refresh(RefreshCommand command) {
        String refreshTokenHash = tokenHasher.hash(command.refreshToken());

        UserSession session = sessionRepository
                .findValidByRefreshTokenHash(refreshTokenHash)
                .orElseThrow(() -> new RuntimeException("Invalid refresh token"));
        if (!session.getDeviceId().equals(command.deviceId())) {
            throw new RuntimeException("Device mismatch");
        }
        sessionRepository.revokeById(session.getId());
        User user = userRepository.findById(session.getUserId())
                .orElseThrow(() -> new RuntimeException("User not found"));
        String newAccessToken = tokenGenerator.generateAccessToken(
                user.getId(),
                user.getRole()
        );

        String newRefreshToken = tokenGenerator.generateRefreshToken(
                session.getUserId()
        );
        Instant now = timeProvider.now();
        UserSession newSession = new UserSession(
                session.getUserId(),
                tokenHasher.hash(newRefreshToken),
                session.getDeviceId(),
                session.getDeviceName(),
                session.getIpAddress(),
                now,
                now.plus(30, ChronoUnit.DAYS),
                null
        );

        sessionRepository.save(newSession);

        return new AuthResult(
                newAccessToken,
                newRefreshToken
        );

    }

    @Override
    public void logout(LogoutCommand command) {
        String refreshTokenHash = tokenHasher.hash(command.refreshToken());
        UserSession session = sessionRepository
                .findValidByRefreshTokenHash(refreshTokenHash)
                .orElseThrow(() -> new RuntimeException("Invalid refresh token"));

        if (!session.getDeviceId().equals(command.deviceId())) {
            throw new RuntimeException("Device mismatch");
        }

        sessionRepository.revokeById(session.getId());
    }
}

