package com.backend.MusicApp.catalog.repository.jdbc;

import com.backend.MusicApp.catalog.entity.Song;
import com.backend.MusicApp.catalog.repository.SongRepository;
import com.backend.MusicApp.catalog.repository.dto.SongProjection;
import lombok.RequiredArgsConstructor;
import org.springframework.dao.EmptyResultDataAccessException;
import org.springframework.jdbc.core.JdbcTemplate;
import org.springframework.jdbc.core.RowMapper;
import org.springframework.stereotype.Repository;

import java.util.List;
import java.util.Optional;

@Repository
@RequiredArgsConstructor
public class JdbcSongRepository implements SongRepository {
    private final JdbcTemplate jdbcTemplate;

    @Override
    public List<SongProjection> findTopNewest(int limit) {
        // Chỉ lấy các trường cần cho danh sách, tránh lấy rác
        String sql = """
            SELECT s.id, s.title, s.cover_url, s.created_at, s.album_id, s.duration_seconds, s.view_count,
            string_agg(a.name, ', ') as artist_name
                           FROM songs s
                           LEFT JOIN song_artists sa ON s.id = sa.song_id
                           LEFT JOIN artists a ON sa.artist_id = a.id
                           GROUP BY s.id, s.title, s.cover_url, s.created_at
                           ORDER BY s.created_at DESC
                           LIMIT ?
        """;
        return jdbcTemplate.query(sql, songProjectionMapper(), limit);
    }

    @Override
    public Optional<SongProjection> findById(Long id) {
        String sql = "SELECT * FROM songs WHERE id = ?"; // Ở đây có thể dùng * nếu cần đầy đủ metadata
        return jdbcTemplate.query(sql, songProjectionMapper(), id)
                .stream().findFirst();
    }

    @Override
    public void incrementViewCount(Long id) {
        jdbcTemplate.update("UPDATE songs SET view_count = view_count + 1 WHERE id = ?", id);
    }

    @Override
    public List<SongProjection> findByAlbumId(Long albumId) {
        String sql = "SELECT id, title, album_id, cover_url, duration_seconds, view_count, created_at " +
                "FROM songs WHERE album_id = ? ORDER BY track_number";
        return jdbcTemplate.query(sql, songProjectionMapper(), albumId);
    }

    // Mapper dùng Lambda để gọn code và dễ bảo trì nội bộ
    private RowMapper<SongProjection> songProjectionMapper() {
        return (rs, rowNum) -> new SongProjection(
                rs.getLong("id"),
                rs.getString("title"),
                rs.getLong("album_id"),
                rs.getString("artist_name"),
                rs.getString("cover_url"),
                rs.getInt("duration_seconds"),
                rs.getLong("view_count"),
                rs.getTimestamp("created_at").toInstant() // Chuyển sang Instant chuẩn bài
        );
    }
}

